var URL = require('url');

exports.action = {
  name: 'login',
  description: 'User login',
  inputs: {
    'required' : [],
    'optional' : ['username', 'password']
  },
  blockedConnectionTypes: [],
  outputExample: {
    success: true
  },
  requireAuth: false,
  
  run: function(api, connection, next){    
    var res = connection.rawConnection.res;
    
    var params = {client_id: api.config.identity.id}
    
    //optionally add username and password
    if(connection.params.username && connection.params.password){
      params.username = connection.params.username;
      params.password = connection.params.password;
    }    
    
    var url = api.identity.site + URL.format({      
      pathname: '/api/oauth/authorize',
      query: params
    });
    
    
    //redirect to identity server
    connection.rawConnection.responseHeaders.push(['Location', url]);
    connection.rawConnection.responseHttpCode = 307;    
    next(connection, true)
  }
};
